SELECT FROM student s LEFT JOIN class_entity c ON s.class_id = c.id WHERE s.is_deleted = 0
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.class_id = #{classId}
ORDER BY s.class_id ASC, s.student_no ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM student s WHERE s.is_deleted = 0
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.class_id = #{classId}

SELECT id, student_no
FROM student
WHERE student_no = #{studentNo}
AND is_deleted = 0

    AND id != #{excludeId}

LIMIT 1
